#!/usr/bin/env node
const fs=require("fs"),path=require("path"),pkg=require("../package.json"),JSON5=require("./"),argv=parseArgs();if(argv.version)version();else if(argv.help)usage();else{const e=argv.defaults[0];let s;s=e?fs.createReadStream(e):process.stdin;let a="";s.on("data",e=>{a+=e}),s.on("end",()=>{let s,t;s="t"===argv.space||"tab"===argv.space?"\t":Number(argv.space);try{if(t=JSON5.parse(a),!argv.validate){const a=JSON.stringify(t,null,s);let r;if(argv.convert&&e&&!argv.outFile){const s=path.parse(e),a=path.format(Object.assign(s,{base:path.basename(s.base,s.ext)+".json"}));r=fs.createWriteStream(a)}else r=argv.outFile?fs.createWriteStream(argv.outFile):process.stdout;r.write(a)}}catch(e){console.error(e.message),process.exit(1)}})}function parseArgs(){let e,s,a,t,r,o;const n=[],i=process.argv.slice(2);for(let c=0;c<i.length;c++){const l=i[c];switch(l){case"--convert":case"-c":e=!0;break;case"--space":case"-s":s=i[++c];break;case"--validate":case"-v":a=!0;break;case"--out-file":case"-o":t=i[++c];break;case"--version":case"-V":r=!0;break;case"--help":case"-h":o=!0;break;default:n.push(l)}}return{convert:e,space:s,validate:a,outFile:t,version:r,help:o,defaults:n}}function version(){console.log(pkg.version)}function usage(){console.log("\n  Usage: json5 [options] <file>\n\n  If <file> is not provided, then STDIN is used.\n\n  Options:\n\n    -s, --space              The number of spaces to indent or 't' for tabs\n    -o, --out-file [file]    Output to the specified file, otherwise STDOUT\n    -v, --validate           Validate JSON5 but do not output JSON\n    -V, --version            Output the version number\n    -h, --help               Output usage information")}